import * as React from 'react';
import {
  Popover,
  PopoverContent,
  PopoverCloseButton,
  PopoverHeader,
  PopoverBody,
  Text,
  PopoverTrigger,
  Box,
  Flex,
  Spinner,
  Tabs,
  TabList,
  TabPanels,
  Tab,
  TabPanel,
  Select,
  Icon,
  Link,
  Progress,
  Button,
} from '@chakra-ui/react';
// import { InfoIcon } from '@chakra-ui/icons';
import { getUserDashboard, UseDashboardData } from '../../services/userDashboard';
import { isNumber } from 'lodash';
import { RiWechatLine } from 'react-icons/ri';
import { BiCodeCurly } from 'react-icons/bi';
import { AiOutlineQuestionCircle, AiOutlineWarning } from 'react-icons/ai';
import { usePostMessage } from '../../PostMessageProvider';
import { useChatBillStore } from '../../store/chatBill';


const UserDashboard = (props: { open: boolean; onClose: () => void }) => {
  const { open, onClose } = props;
  const { postMessage } = usePostMessage();
  // const [showMore, setShowMore] = React.useState(false);
  const [data, setData] = React.useState<UseDashboardData | null>(null);
  const [loading, setLoading] = React.useState(false);
  const billLoading = useChatBillStore(state => state.billLoading)
  const monthlyBills = useChatBillStore(state => state.monthlyBills)
  const maxCostPerMonth = useChatBillStore(state => state.maxCostPerMonth)
  const { currentMonth = '-', lastMonth = '-', prevMonth = '-' } = React.useMemo(() => {
    if (!monthlyBills.length) return {}
    return {
      currentMonth: monthlyBills[0].time,
      lastMonth: monthlyBills[1].time,
      prevMonth: monthlyBills[2].time
    };
  }, [monthlyBills]);

  // 设置默认选中当前月份
  const [selectedMonth, setSelectedMonth] = React.useState('');

  React.useEffect(() => {
    setSelectedMonth(currentMonth)
  }, [currentMonth])

  React.useEffect(() => {
    if (open) {
      setLoading(true);
      getUserDashboard()
        .then((data) => {
          if (data) {
            setData(data);
          }
        }).finally(() => {
          setLoading(false);
        })
    }
  }, [open]);



  // 格式化月份显示
  const formatMonthDisplay = React.useCallback((monthStr: string): string => {
    const [year, month] = monthStr.split('-');
    return `${year || '-'}年 ${month || '-'}月`;
  }, []);


  // 获取统计时间范围（往前倒退90天）
  const getTime = React.useCallback((): string => {
    const { last_access_time } = data || {};
    let endDate: Date;

    if (last_access_time) {
      // 如果存在 last_access_time，使用这个时间作为结束时间
      // last_access_time 是秒级时间戳，需要转换为毫秒级
      const timestamp = typeof last_access_time === 'string' ? parseInt(last_access_time, 10) : last_access_time;
      endDate = new Date(timestamp * 1000);

      // 检查日期是否有效
      if (isNaN(endDate.getTime())) {
        // 如果解析失败，使用今天的0点
        endDate = new Date();
        endDate.setHours(0, 0, 0, 0);
      }
    } else {
      // 如果不存在，使用今天的0点作为结束时间
      endDate = new Date();
      endDate.setHours(0, 0, 0, 0);
    }

    // 计算开始时间（往前倒退90天）
    const startDate = new Date(endDate);
    startDate.setDate(startDate.getDate() - 90);

    return `${startDate.toLocaleString()} - ${endDate.toLocaleString()}`;
  }, [data]);


  const currentCost = React.useMemo(() => {
    const bill = monthlyBills.find(item => item.time === selectedMonth);
    return bill?.usageCost || 0;
  }, [monthlyBills, selectedMonth]);
  const currentPoints = React.useMemo(() => Math.floor(currentCost * 100), [currentCost]);
  const maxIntegral = React.useMemo(() => Math.floor(maxCostPerMonth * 100), [maxCostPerMonth]);
  const isExceeded = React.useMemo(() => currentPoints > maxIntegral, [currentPoints, maxIntegral]);
  const progressValue = React.useMemo(() => {
    if (maxIntegral <= 0) return 0;
    return Math.min((currentPoints / maxIntegral) * 100, 100);
  }, [currentPoints, maxIntegral]);

  return (
    <>
      <Popover
        placement="top-end"
        isOpen={open}
        onClose={onClose}
        closeOnBlur={false}
      >
        <PopoverTrigger>
          <Box
            position="fixed"
            top="0px"
            right="10px"
            width="1px"
            height="1px"
            opacity={0}
            pointerEvents="none"
          />
        </PopoverTrigger>
        <PopoverContent bg="#1A1A1A" borderColor="#343434" color="white" w="320px" boxShadow={'base'}>
          <PopoverHeader borderBottom="none" pt={4} px={4}>
            <Flex alignItems="center">
              <Box as="span" mr={2} color="blue.400">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 2L2 7l10 5 10-5-10-5zm0 9l2.5-1.25L12 8.5l-2.5 1.25L12 11zm0 2.5l-5-2.5-5 2.5L12 22l10-8.5-5-2.5-5 2.5z" />
                </svg>
              </Box>
              <Text fontWeight="bold" fontSize="md">CodeMaker 数据统计</Text>
            </Flex>
          </PopoverHeader>
          <PopoverCloseButton top="12px" color="gray.400" />

          <PopoverBody p={0}>
            <Tabs isFitted variant="unstyled" mt={2}>
              <TabList mx={4} bg="#242525" borderRadius="md" p={1}>
                <Tab
                  _selected={{ bg: '#454545', color: 'white' }}
                  color="gray.400"
                  borderRadius="md"
                  fontSize="sm"
                  py={1}
                >
                  消耗统计
                </Tab>
                <Tab
                  _selected={{ bg: '#454545', color: 'white' }}
                  color="gray.400"
                  borderRadius="md"
                  fontSize="sm"
                  py={1}
                >
                  功能用量
                </Tab>
              </TabList>
              <TabPanels>
                <TabPanel px={6} py={4}>
                  {
                    billLoading ? (
                      <Flex w="full" minH="200px" direction="column" alignItems="center" justifyContent="center">
                        <Spinner />
                        <Text mt="2" color={'gray.400'}>正在为您加载数据，请稍候...</Text>
                      </Flex>
                    ) : (
                      <>
                        <Flex justifyContent="space-between" alignItems="center" mb={4}>
                          <Flex alignItems={'center'} justifyContent={'center'}>
                            <Text fontWeight="bold" fontSize="sm">仓库智聊消耗情况</Text>
                          </Flex>
                          <Select
                            size="sm"
                            w="110px"
                            borderColor="gray.600"
                            value={selectedMonth}
                            style={{ zoom: .9 }}
                            onChange={(e) => setSelectedMonth(e.target.value)}
                          >
                            <option value={currentMonth}>{formatMonthDisplay(currentMonth)}</option>
                            <option value={lastMonth}>{formatMonthDisplay(lastMonth)}</option>
                            <option value={prevMonth}>{formatMonthDisplay(prevMonth)}</option>
                          </Select>
                        </Flex>

                        <Box bg="#2d2e30" borderRadius="md" p={4} mb={4}>
                          <Flex color="gray.400" fontSize="sm" mb={2}>
                            截止当月累计消耗
                            <ConsumeTenkenTip className='mb-1' />
                          </Flex>
                          <Flex alignItems="baseline" mb={3} flexWrap={'wrap'}>
                            <Text fontSize="xl" fontWeight="bold" mr={2}>
                              {billLoading ? '-' : currentPoints.toLocaleString()} 积分
                            </Text>
                            <Text color="gray.500" fontSize="sm">({billLoading ? '-' : currentCost.toFixed(1)} 元)</Text>
                          </Flex>

                          <Progress
                            value={progressValue}
                            size="sm"
                            colorScheme="blue"
                            borderRadius="full"
                            bg="gray.600"
                            mb={2}
                            sx={{
                              '& > div': {
                                backgroundColor: 'blue.400'
                              }
                            }}
                          />

                          <Flex justifyContent="space-between" alignItems="center" fontSize="xs">
                            <Flex alignItems="center" visibility={isExceeded ? 'visible' : 'hidden'}>
                              <Icon as={AiOutlineWarning} color="blue.400" mr={1} />
                              <Text color="blue.300">已超出限额</Text>
                            </Flex>
                            <Text color="gray.500">
                              {currentPoints.toLocaleString()}/{maxIntegral.toLocaleString()} 积分
                            </Text>
                          </Flex>
                        </Box>
                        {
                          (
                            <Box color={'gray.500'} fontSize={'small'} style={{ zoom: .92 }}>
                              若因工作需要提升积分额度，可参阅
                              <Button
                                size="sm"
                                variant="link"
                                color="blue.600"
                                fontWeight="600"
                                onClick={(e: React.MouseEvent) => {
                                  e.stopPropagation();
                                  postMessage({
                                    type: "OPEN_IN_BROWSER",
                                    data: { url: `https://g.126.fm/01ePpyp` },
                                  });
                                }}
                                _hover={{ textDecoration: 'none', opacity: 0.8 }}
                              >
                                《积分申请》
                              </Button>
                            </Box>
                          )
                        }
                      </>
                    )
                  }
                </TabPanel>
                <TabPanel px={6} py={4}>
                  <Text color="gray.400" fontSize="sm" mb={1}>
                    近 3 个月你的 CodeMaker 用量为：
                  </Text>
                  <Text color="gray.400" fontSize="sm" mb={4}>
                    {getTime()}
                  </Text>
                  {loading ? (
                    <Flex w="full" minH="200px" direction="column" alignItems="center" justifyContent="center">
                      <Spinner />
                      <Text mt="2" color={'gray.400'}>正在为您加载数据，请稍候...</Text>
                    </Flex>
                  ) : (
                    <>
                      <Box mb="4">
                        <Flex alignItems="center" mb={2}>
                          <Text color="#50A9DE"><BiCodeCurly /></Text>
                          <Text fontWeight="bold">【代码补全】</Text>
                        </Flex>
                        <Box ml="6" fontSize="sm" color="gray.300">
                          <Flex justifyContent="space-between" mb={1}>
                            <Text>• 累计使用天数：</Text>
                            <Text>{data?.complete_use_days || 0}天</Text>
                          </Flex>
                          <Flex justifyContent="space-between" mb={1}>
                            <Text>• 累计采纳代码次数：</Text>
                            <Text>{data?.complete_accept_nums || 0}次</Text>
                          </Flex>
                          <Flex justifyContent="space-between">
                            <Text>• 代码补全接受率：</Text>
                            <Text>
                              {isNumber(data?.complete_accept_ratio)
                                ? (data?.complete_accept_ratio * 100).toFixed(2)
                                : 0}
                              %
                            </Text>
                          </Flex>
                        </Box>
                      </Box>

                      <Box mb="4">
                        <Flex alignItems="center" mb={2}>
                          <Text color="blue.300"><RiWechatLine color="blue.300" size={16} /></Text>
                          <Text fontWeight="bold">【仓库智聊】</Text>
                        </Flex>
                        <Box ml="6" fontSize="sm" color="gray.300">
                          <Flex justifyContent="space-between" mb={1}>
                            <Text>• 聊天次数：</Text>
                            <Text>{data?.gitchat_total || 0}次</Text>
                          </Flex>
                          <Flex justifyContent="space-between">
                            <Text>• 生成与应用代码行数：</Text>
                            <Text>{data?.gitchat_generate_lines || 0}行</Text>
                          </Flex>
                        </Box>
                      </Box>

                      <Box mb="2">
                        <Flex alignItems="center" mb={2}>
                          <Icon viewBox="0 0 24 24" color="green.300">
                            <path fill="currentColor" d="M15.5 14h-.79l-.28-.27C15.41 12.59 16 11.11 16 9.5 16 5.91 13.09 3 9.5 3S3 5.91 3 9.5 5.91 16 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z" />
                          </Icon>
                          <Text fontWeight="bold">【Local AI Review】</Text>
                        </Flex>
                        <Box ml="6" fontSize="sm" color="gray.300">
                          <Flex justifyContent="space-between" mb={1}>
                            <Text>• 发起 AI Review 次数：</Text>
                            <Text>{data?.localreview_start_nums || 0}次</Text>
                          </Flex>
                          <Flex justifyContent="space-between">
                            <Text>• 反馈有效/无效问题个数：</Text>
                            <Text>{data?.localreview_post_issue_nums || 0}个</Text>
                          </Flex>
                        </Box>
                      </Box>
                    </>
                  )}
                </TabPanel>
              </TabPanels>
            </Tabs>
          </PopoverBody>
        </PopoverContent>
      </Popover>
    </>
  );
};

export default UserDashboard;


export const ConsumeTenkenTip = ({
  className,
}: {
  className?: string;
}) => {
  const { postMessage } = usePostMessage();
  const QAGroup = React.useMemo(() => ([
    {
      title: '什么是积分？',
      content: '积分是AIGW用于统一模型消耗的统一单位，1积分等于0.01元，具体可用Token数与所选模型单价相关。'
    },
    {
      title: '为什么展示积分？',
      content: '近期发现部分用户无节制的使用CodeMaker，产生了超出正常使用的成本，也影响到其他人使用。为了量化每个会话资源消耗，方便CodeMaker团队分析成本构成，推进技术优化，我们将消耗Token数升级为积分数，并给出实际成本消耗预估。'
    },
    {
      title: '私有模型也算积分吗？',
      content: '私有部署也是要服务器的，目前我们用的有道的私有部署服务，单价由有道来定。',
    },
    {
      title: '后续CodeMaker是否会收费，面向团队或是个人？',
      content: '不会面向个人收费，具体分摊方案还在制定中。',
    },
    {
      title: '如何高效使用？',
      content: (
        <>
          <Text mb={1}>* 按需选模型（省流）： 不同模型成本差异巨大。对于翻译、简单润色等任务，推荐使用高性价比模型（如 Claude Haiku）。</Text>
          <Text mb={1}>* 及时开启新对话（提速）： 避免在一个会话中无限追加提问。历史记录过长不仅消耗成倍的 Token，还会影响模型响应速度。开启新会话，从头开始更高效。</Text>
          <Text>* 优化提示词（精准）： 尽量一次性给出清晰、完整的指令和背景信息，减少反复纠偏造成的额度浪费。</Text>
        </>
      )
    },
    {
      title: '哪个模型最便宜？各模型单价在哪看？',
      content: (
        <>
          <Link
            color="blue.300"
            px="1"
            onClick={() => {
              postMessage({
                type: 'OPEN_IN_BROWSER',
                data: {
                  url: 'https://modelspace.netease.com/model_app',
                },
              });
            }}
          >
            模型详细介绍
          </Link>
          (费用 = 模型单价 * tokens)
        </>
      )
    }
  ]), [postMessage])

  return (
    <Box className={className}>
      <Popover placement="top-start" trigger="hover" openDelay={0} closeDelay={200}>
        <PopoverTrigger>
          <Box ml={1}>
            <Icon as={AiOutlineQuestionCircle} size="sm" />
          </Box>
        </PopoverTrigger>
        <PopoverContent
          boxShadow="xl"
          minWidth={"320px"}
          _focus={{ boxShadow: "xl" }}
          borderRadius="lg"
        >
          <PopoverBody px={4} py={2}>
            <Box className='space-y-4'>
              {QAGroup.map((group, index) => (
                <Box key={group.title + index}>
                  <Box fontWeight={'bold'} mb={1}>
                    {index + 1}. {group.title}
                  </Box>
                  <Box>{group.content}</Box>
                </Box>
              ))}
            </Box>
          </PopoverBody>
        </PopoverContent>
      </Popover >
    </Box>
  )
}

import * as React from 'react';
import {
  Flex,
  Box,
  Text,
  Popover,
  PopoverTrigger,
  PopoverContent,
  PopoverHeader,
  PopoverCloseButton,
  PopoverBody,
  IconButton,
  VStack,
  Button,
  Spacer,
  Tooltip,
  Input,
  PopoverArrow,
  PopoverFooter,
  ButtonGroup,
  useMediaQuery,
  Portal,
  Spinner,
} from '@chakra-ui/react';
import { ChatIcon } from '@chakra-ui/icons';
import { TbClockHour3, TbCheck } from 'react-icons/tb';
import { RiFileEditLine, RiDeleteBinLine } from 'react-icons/ri';
import { IoMdClose } from 'react-icons/io';
import {
  useChatStore,
  useChatStreamStore,
  DEFAULT_TOPIC,
  requestChatSessions,
  ChatSession,
} from '../../store/chat';
import { DateFormat, alphabeticalCompare } from '../../utils';
import userReporter from '../../utils/report';
import useCustomToast from '../../hooks/useCustomToast';
import Icon from '../../components/Icon';
import { scrollToFocusItem } from './ChatTypeAhead/utils';
import { toastErrorMessage } from '../../utils';
import { useChatConfig } from '../../store/chat-config';
import { getHistories } from '../../services/chat';
import { debounce, isNumber } from 'lodash';
import { MdInbox } from 'react-icons/md';
import {
  SmallScreenWidth,
  MediumScreenWidth,
  LargeScreenWidth,
} from '../../const';
import { BsDatabase } from 'react-icons/bs';
import { ChatMessageContent } from '../../services/index';
import { useCodeChatContext } from './CodeChatProvider';
import { Select } from 'chakra-react-select';
import { RiArrowDownSLine } from 'react-icons/ri';
import { nanoid } from 'nanoid';
import { useWorkspaceStore } from '../../store/workspace';
import CustomCollapse from '../../components/Collapse';
import { useTerminalMessage } from './ChatMessagesList/TermialPanel';
import { UserEvent } from '../../types/report';
import { ChatModel } from '../../services/chatModel';

interface NewChatSession extends ChatSession {
  disabled?: boolean;
}
export interface ChatHistoriesHandle {
  isOpen: boolean;
}
interface SearchMessageResult extends ChatSession {
  content: string;
  messageId: string;
  role: string;
  messages: [];
  context: string;
}
enum SearchField {
  Topic = 'topic',
  Content = 'topic_content',
}

const searchOptions = [
  { label: '内容', value: SearchField.Content },
  { label: '标题', value: SearchField.Topic },
];

interface SessionItemProps {
  item: ChatSession;
  index: number;
  isStreaming: boolean;
  isSearching: boolean;
  currentSessionId: string | undefined;
  onSelect: (id: string) => void;
  onUpdateTopic: (id: string, topic: string) => Promise<void>;
  onDelete: (id: string) => void;
}

const SessionItemComponent = React.memo(
  ({
    item,
    index,
    isStreaming,
    isSearching,
    currentSessionId,
    onSelect,
    onUpdateTopic,
    onDelete,
  }: SessionItemProps) => {
    const [isEditing, setIsEditing] = React.useState(false);
    const [editValue, setEditValue] = React.useState(item.topic || '');
    const updateTime = item.metadata?.update_time;
    const messageLength = isNumber(item.message_count)
      ? item.message_count
      : item.data?.messages.length;
    const [removeConfirmOpen, setRemoveConfirmOpen] = React.useState(false);

    const isDisabled = isStreaming || isSearching;

    return (
      <Box
        data-index={index}
        h="full"
        w="full"
        borderRadius="8px"
        px={2}
        my={1}
        onClick={(e) => {
          if (isDisabled) return;
          e.stopPropagation();
          onSelect(item._id);
        }}
        _hover={isDisabled ? {} : { backgroundColor: 'blue.300' }}
        bg={currentSessionId === item._id ? 'blue.300' : 'panelBgColor'}
        opacity={isDisabled ? 0.5 : 1}
        cursor={isDisabled ? 'not-allowed' : 'pointer'}
      >
        <Box textAlign="left" w="full" py={2} flex={1}>
          <Flex justify="space-between" align="center" mb={1}>
            {isEditing ? (
              <>
                <Input
                  type="text"
                  value={editValue}
                  border="1px solid #fff"
                  maxW="160px"
                  onChange={(e) => {
                    e.stopPropagation();
                    setEditValue(e.target.value);
                  }}
                  onClick={(e) => e.stopPropagation()}
                  autoFocus
                />
                <Box>
                  <IconButton
                    aria-label="确定"
                    variant="ghost"
                    size="xs"
                    icon={<Icon as={TbCheck} size="sm" />}
                    className="mr-1"
                    onClick={async (e) => {
                      e.stopPropagation();
                      await onUpdateTopic(item._id, editValue);
                      setIsEditing(false);
                    }}
                  />
                  <IconButton
                    aria-label="取消"
                    variant="ghost"
                    size="xs"
                    icon={<Icon as={IoMdClose} size="sm" />}
                    onClick={(e) => {
                      e.stopPropagation();
                      setIsEditing(false);
                    }}
                  />
                </Box>
              </>
            ) : (
              <Box
                w="full"
                display="flex"
                justifyContent="space-between"
                minH="20px"
              >
                <Text title={item.topic || DEFAULT_TOPIC} fontSize="sm" isTruncated maxW="160px">
                  <ChatIcon w={8} fontSize="sm" />
                  {item.topic || DEFAULT_TOPIC}
                </Text>

                {!(item as NewChatSession)?.disabled && (
                  <Box>
                    <IconButton
                      aria-label="编辑"
                      variant="ghost"
                      size="xs"
                      icon={<Icon as={RiFileEditLine} size="sm" />}
                      isDisabled={isStreaming || isSearching}
                      color="text.default"
                      onClick={(e) => {
                        e.stopPropagation();
                        setIsEditing(true);
                        setEditValue(item.topic || '');
                      }}
                    />
                    <Popover
                      placement="bottom"
                      closeOnBlur={true}
                      strategy="fixed"
                      isOpen={removeConfirmOpen}
                      isLazy
                    >
                      <PopoverTrigger>
                        <IconButton
                          aria-label="删除会话"
                          size="xs"
                          icon={<Icon as={RiDeleteBinLine} size="sm" />}
                          bg="none"
                          isDisabled={isStreaming || isSearching}
                          onClick={(e) => {
                            e.stopPropagation();
                            setRemoveConfirmOpen(true);
                          }}
                          color="text.default"
                        />
                      </PopoverTrigger>
                      <PopoverContent>
                        <PopoverHeader pt={4} fontWeight="bold" border="0">
                          删除当前会话
                        </PopoverHeader>
                        <PopoverArrow />
                        <PopoverBody>
                          确定删除吗？删除后会话将不可恢复。
                        </PopoverBody>
                        <PopoverFooter
                          border="0"
                          display="flex"
                          alignItems="center"
                          justifyContent="space-between"
                          pb={4}
                        >
                          <ButtonGroup size="sm">
                            <Button
                              variant="outline"
                              onClick={(e) => {
                                e.stopPropagation();
                                setRemoveConfirmOpen(false);
                              }}
                            >
                              取消
                            </Button>
                            <Button
                              colorScheme="blue"
                              color="white"
                              onClick={(e) => {
                                e.stopPropagation();
                                onDelete(item._id);
                                setRemoveConfirmOpen(false);
                              }}
                            >
                              删除
                            </Button>
                          </ButtonGroup>
                        </PopoverFooter>
                      </PopoverContent>
                    </Popover>
                  </Box>
                )}
              </Box>
            )}
          </Flex>
          {item?.chat_type === 'codebase' && item?.chat_repo && (
            <Box display="flex" alignItems="center" pl={2} mb={2}>
              <Flex gap={1} alignItems="center" isTruncated>
                <BsDatabase fontSize={12} />
                <Text ml={1} fontSize={12}>
                  {item?.chat_repo || '-'}
                </Text>
              </Flex>
            </Box>
          )}

          <Flex>
            <Text fontSize="xs" opacity="0.5" pl={2} isTruncated>
              {updateTime &&
                DateFormat(new Date(updateTime), 'YYYY-MM-DD HH:mm:ss')}
            </Text>
            <Spacer />
            {messageLength ? (
              <Text fontSize="xs" opacity="0.5" pr={2}>
                {messageLength} 条对话
              </Text>
            ) : null}
          </Flex>
        </Box>
      </Box>
    );
  },
);
const ChatHistories = React.forwardRef((_, ref) => {
  const isStreaming = useChatStreamStore((state) => state.isStreaming);
  const isProcessing = useChatStreamStore((state) => state.isProcessing);
  const isTerminalProcessing = useChatStreamStore((state) => state.isTerminalProcessing);
  const isSearching = useChatStreamStore((state) => state.isSearching);
  const [isOpen, setIsOpen] = React.useState(false);
  const popoverRef = React.useRef<HTMLDivElement>(null);
  const [
    sessions,
    currentSession,
    selectSession,
    updateTopic,
    removeSession,
    revalidateChatSessions,
    chatType,
  ] = useChatStore((state) => [
    state.sessions,
    state.currentSession(),
    state.selectSession,
    state.updateTopic,
    state.removeSession,
    state.revalidateChatSessions,
    state.chatType,
  ]);

  const updateModel = useChatConfig((state) => state.update);
  const [searchKeyword, setSearchKeyword] = React.useState('');
  const [searchSessions, setSearchSessions] = React.useState<NewChatSession[]>(
    [],
  );
  const abortControllerRef = React.useRef<AbortController | null>(null);
  const [isSmallScreen] = useMediaQuery(SmallScreenWidth);
  const [isMediumScreen] = useMediaQuery(MediumScreenWidth);
  const [isLargerThan340] = useMediaQuery(LargeScreenWidth);
  const [selectedMessageId, setSelectedMessageId] = React.useState('');
  const { chatMessagesRef } = useCodeChatContext();
  const [loading, setLoading] = React.useState(false);
  const [searchField, setSearchField] = React.useState(searchOptions[0]);
  const [currentPage, setCurrentPage] = React.useState(1);
  const [scrollLoading, setScrollLoading] = React.useState(false);
  const [isNext, setIsNext] = React.useState(true);
  const workspaceInfo = useWorkspaceStore((state) => state.workspaceInfo);
  const [currentRepoOpen, setCurrentRepoOpen] = React.useState(true);
  const [otherRepoOpen, setOtherRepoOpen] = React.useState(true);
  const { stopRunningTerminal } = useTerminalMessage();

  const updateSessions = React.useCallback(async () => {
    const data = await requestChatSessions();
    revalidateChatSessions(data.items, chatType);
  }, [revalidateChatSessions, chatType]);

  const { toast } = useCustomToast();

  const handleDelete = React.useCallback(
    async (sessionId: string) => {
      userReporter.report({
        event: UserEvent.CODE_CHAT_REMOVE_SESSION,
      });
      if (!sessionId) {
        return;
      }
      try {
        await removeSession(sessionId);
        await updateSessions();
        toast({
          title: '删除成功',
          position: 'top',
          isClosable: true,
          duration: 1000,
          status: 'success',
        });
      } catch (error) {
        console.log(error);
        toast({
          title: toastErrorMessage(error as Error),
          position: 'top',
          isClosable: true,
          status: 'error',
        });
      }
    },
    [removeSession, updateSessions, toast],
  );

  // 排序
  const renderSessions = React.useMemo(
    () =>
      Array.from(sessions.values())
        .sort((a, b) =>
          alphabeticalCompare(b.metadata.create_time, a.metadata.create_time),
        )
        .filter((session) => session.chat_type === chatType),
    [sessions, chatType],
  );

  React.useImperativeHandle(ref, () => ({
    isOpen: isOpen,
  }));

  const handleSelectSession = React.useCallback(
    (id: string) => {
      if (isStreaming || isProcessing || isTerminalProcessing || isSearching) {
        toast({
          title: 'CodeMaker 正在回复，请稍后再切换会话',
          status: 'warning',
          position: 'top',
          isClosable: true,
        });
        return;
      }
      if (currentSession?._id === id) {
        toast({
          title: '当前已是所选对话',
          status: 'info',
        });
        return;
      }
      const nextSession = sessions.get(id);
      const model = nextSession?.data?.model;
      // 如果会话有模型，直接用模型即可
      if (model) {
        updateModel((config) => {
          config.model = model as ChatModel;
          return config;
        });
      }
      stopRunningTerminal();
      selectSession(id);
    },
    [
      isStreaming,
      isProcessing,
      isTerminalProcessing,
      isSearching,
      currentSession?._id,
      sessions,
      selectSession,
      toast,
      updateModel,
      stopRunningTerminal,
    ],
  );

  const handleSelectSessionAndScrollToMessage = React.useCallback(
    (session: SearchMessageResult) => {
      if (isStreaming || isProcessing || isTerminalProcessing || isSearching) {
        toast({
          title: 'CodeMaker 正在回复，请稍后再切换会话',
          status: 'warning',
          position: 'top',
          isClosable: true,
        });
        return;
      }
      const nextSession = sessions.get(session._id);
      if (nextSession?._id !== currentSession?._id) {
        const model = nextSession?.data?.model;
        if (model) {
          updateModel((config) => {
            config.model = model as ChatModel;
            return config;
          });
        }
        selectSession(session._id, () => {
          setTimeout(() => {
            chatMessagesRef.current?.scrollToMessage(
              session.role,
              session.messageId,
              searchKeyword,
            );
          }, 0);
        });
      } else {
        // 如果是在本次会话中，直接定位到改会话即可
        chatMessagesRef.current?.scrollToMessage(
          session.role,
          session.messageId,
          searchKeyword,
        );
      }

      setSelectedMessageId(`${session.role}-${session.messageId}`);
    },
    [
      isStreaming,
      isProcessing,
      isTerminalProcessing,
      isSearching,
      selectSession,
      sessions,
      updateModel,
      toast,
      chatMessagesRef,
      currentSession,
      searchKeyword,
    ],
  );

  const handleOpenPopover = () => {
    userReporter.report({
      event: UserEvent.CODE_CHAT_VIEW_SESSIONS,
    });
    setIsOpen((prev) => !prev);
    setTimeout(() => {
      if (!isOpen && popoverRef.current) {
        const index = renderSessions.findIndex(
          (item) => item._id === currentSession?._id,
        );
        scrollToFocusItem(popoverRef.current, index);
      }
    });
  };

  const resetLoadMore = React.useCallback(() => {
    setIsNext(true);
    setCurrentPage(1);
  }, []);

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const debouncedGetSessions = React.useCallback(
    debounce(async (keyword: string) => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
      const controller = new AbortController();
      abortControllerRef.current = controller;
      try {
        setLoading(true);
        setSearchSessions([]);
        const params = {
          _num: 10,
          _page: 1,
          _sort_by: '-metadata.create_time',
          [searchField.value]: keyword.trim(),
          chat_type: chatType,
        };
        if (searchField.value === SearchField.Topic) {
          params._exclude = 'data';
        }
        const data = await getHistories(params, controller.signal);
        setLoading(false);
        setSearchSessions(data?.items || []);
        resetLoadMore();
      } catch (error) {
        setSearchSessions([]);
        setLoading(false);
        console.error(error);
      }
    }, 500),
    [searchField, chatType],
  );

  React.useEffect(() => {
    if (!searchKeyword.trim()) return;
    debouncedGetSessions(searchKeyword);
    return () => {
      debouncedGetSessions.cancel();
    };
  }, [searchKeyword, debouncedGetSessions]);

  const filterSessions = React.useMemo(() => {
    if (!searchKeyword.trim()) return renderSessions;
    return Array.from(searchSessions.values())
      .filter((session) => session.chat_type === chatType)
      .map((session) => ({ ...session, disabled: true }));
  }, [searchKeyword, renderSessions, searchSessions, chatType]);

  const searchMessages: SearchMessageResult[] = React.useMemo(() => {
    if (!searchKeyword.trim()) return [];
    return filterSessions.flatMap((session) =>
      (session.data?.messages || []).map((message) => {
        let content = '';
        if (message.content instanceof Array) {
          content =
            message.content.find((i) => i.type === ChatMessageContent.Text)
              ?.text || '';
        } else {
          content = message.content;
        }
        const context = extractContext(content, searchKeyword);
        return {
          ...session,
          messages: [], // 清空原有的messages数组
          content,
          messageId: message.id || '',
          role: message.role,
          context,
        };
      }),
    );
  }, [filterSessions, searchKeyword]);

  const handleReset = () => {
    setSearchKeyword('');
    setSelectedMessageId('');
    chatMessagesRef.current?.removeAllHighlights();
  };

  const calcScreenWidth = React.useMemo(() => {
    if (isSmallScreen) {
      return {
        width: '140px',
      };
    }
    if (isMediumScreen) {
      return {
        width: '220px',
      };
    }
    if (isLargerThan340) {
      return {};
    }
  }, [isLargerThan340, isMediumScreen, isSmallScreen]);

  const renderSearchItem = React.useMemo(() => {
    if (loading) return <LoadingState />;
    const SessionItem = ({
      item,
      index,
    }: {
      item: ChatSession;
      index: number;
    }) => {
      // const updateTime = item.metadata?.update_time;
      // const messageLength = isNumber(item.message_count)
      //   ? item.message_count
      //   : item.data?.messages.length;
      const key = item._id + (item.topic || '') + (item.user || '') + index;

      return (
        <SessionItemComponent
          key={key}
          item={item}
          index={index}
          isStreaming={isStreaming}
          isSearching={isProcessing || isTerminalProcessing || isSearching}
          currentSessionId={currentSession?._id}
          onSelect={handleSelectSession}
          onUpdateTopic={updateTopic}
          onDelete={handleDelete}
        />
      );
    };

    const MessageItem = ({
      item,
      index,
    }: {
      item: SearchMessageResult;
      index: number;
    }) => {
      const updateTime = item.metadata?.update_time;
      const messageId = item.messageId ? item.messageId : nanoid();
      const key = `${item._id}-${item.role}-${messageId}`;
      const isCurrent =
        currentSession?._id === item._id && key === selectedMessageId;

      const isDisabled = isStreaming || isProcessing || isTerminalProcessing || isSearching;

      return (
        <Button
          data-index={index}
          h="full"
          w="full"
          px={2}
          my={1}
          key={key}
          onClick={() => {
            if (isDisabled) return;
            handleSelectSessionAndScrollToMessage(item);
          }}
          isDisabled={isDisabled}
          _hover={isDisabled ? {} : { backgroundColor: 'blue.300' }}
          bg={isCurrent ? 'blue.300' : undefined}
        >
          <Box textAlign="left" w="full" py={2} flex={1}>
            <Flex justify="space-between" align="center" mb={1}>
              <Box
                w="full"
                display="flex"
                justifyContent="space-between"
                minH="20px"
              >
                <Text fontSize="sm" isTruncated maxW="160px">
                  <ChatIcon w={8} fontSize="sm" />
                  {item.context}
                </Text>
              </Box>
            </Flex>
            {item?.chat_type === 'codebase' && item?.chat_repo && (
              <Box display="flex" alignItems="center" pl={2} mb={2}>
                <Flex gap={1} alignItems="center" isTruncated>
                  <BsDatabase fontSize={12} />
                  <Text ml={1} fontSize={12}>
                    {item?.chat_repo || '-'}
                  </Text>
                </Flex>
              </Box>
            )}

            <Flex>
              <Text fontSize="xs" opacity="0.5" pl={2} isTruncated>
                {updateTime &&
                  DateFormat(new Date(updateTime), 'YYYY-MM-DD HH:mm:ss')}
              </Text>
              <Spacer />
            </Flex>
          </Box>
        </Button>
      );
    };

    const RepoSessionsList = ({
      currentRepo,
      otherRepo,
    }: {
      currentRepo: ChatSession[];
      otherRepo: ChatSession[];
    }) => (
      <Box>
        <CustomCollapse
          title="当前仓库会话"
          isOpen={currentRepoOpen}
          onToggle={() => {
            setCurrentRepoOpen(!currentRepoOpen);
          }}
        >
          {currentRepo.map((item, index) => (
            <SessionItem key={item._id} item={item} index={index} />
          ))}
        </CustomCollapse>

        <Box mt="2">
          <CustomCollapse
            title="其他仓库会话"
            isOpen={otherRepoOpen}
            onToggle={() => {
              setOtherRepoOpen(!otherRepoOpen);
            }}
          >
            {otherRepo.map((item, index) => (
              <SessionItem key={item._id} item={item} index={index} />
            ))}
          </CustomCollapse>
        </Box>
      </Box>
    );

    const RepoMessagesList = ({
      currentRepo,
      otherRepo,
    }: {
      currentRepo: SearchMessageResult[];
      otherRepo: SearchMessageResult[];
    }) => (
      <Box>
        <CustomCollapse
          title="当前仓库会话"
          isOpen={currentRepoOpen}
          onToggle={() => {
            setCurrentRepoOpen(!currentRepoOpen);
          }}
        >
          {currentRepo.map((item, index) => (
            <MessageItem
              key={`${item._id}-${index}`}
              item={item}
              index={index}
            />
          ))}
        </CustomCollapse>

        <Box mt="2">
          <CustomCollapse
            title="其他仓库会话"
            isOpen={otherRepoOpen}
            onToggle={() => {
              setOtherRepoOpen(!otherRepoOpen);
            }}
          >
            {otherRepo.map((item, index) => (
              <MessageItem
                key={`${item._id}-${index}`}
                item={item}
                index={index}
              />
            ))}
          </CustomCollapse>
        </Box>
      </Box>
    );
    if (!searchKeyword.trim().length) {
      // 无会话数据时显示空状态
      if (!renderSessions.length) return <EmptyState />;

      // 有会话数据时显示列表
      if (chatType === 'codebase') {
        // 代码库类型的处理逻辑
        const currentRepoList = renderSessions.filter(
          (i) => i.chat_repo === workspaceInfo.repoName,
        );
        const otherRepoList = renderSessions.filter(
          (i) => i.chat_repo !== workspaceInfo.repoName,
        );
        return (
          <RepoSessionsList
            currentRepo={currentRepoList}
            otherRepo={otherRepoList}
          />
        );
      }

      return renderSessions.map((item, index) => (
        <SessionItem key={item._id} item={item} index={index} />
      ));
    }
    // 有搜索关键词的情况
    if (searchField.value === SearchField.Topic && !filterSessions.length)
      return <EmptyState />;
    if (searchField.value !== SearchField.Topic && !searchMessages.length)
      return <EmptyState />;

    if (!searchKeyword.trim().length) {
      if (chatType === 'codebase') {
        const currentRepoList = renderSessions.filter(
          (i) => i.chat_repo === workspaceInfo.repoName,
        );
        const otherRepoList = renderSessions.filter(
          (i) => i.chat_repo !== workspaceInfo.repoName,
        );
        return (
          <RepoSessionsList
            currentRepo={currentRepoList}
            otherRepo={otherRepoList}
          />
        );
      }

      return renderSessions.map((item, index) => (
        <SessionItem key={item._id} item={item} index={index} />
      ));
    }

    if (searchField.value === SearchField.Topic) {
      if (chatType === 'codebase') {
        const currentRepoList = filterSessions.filter(
          (i) => i.chat_repo === workspaceInfo.repoName,
        );
        const otherRepoList = filterSessions.filter(
          (i) => i.chat_repo !== workspaceInfo.repoName,
        );
        return (
          <RepoSessionsList
            currentRepo={currentRepoList}
            otherRepo={otherRepoList}
          />
        );
      }

      return filterSessions.map((item, index) => (
        <SessionItem key={item._id} item={item} index={index} />
      ));
    }

    if (chatType === 'codebase') {
      const currentRepoList = searchMessages.filter(
        (i) => i.chat_repo === workspaceInfo.repoName,
      );
      const otherRepoList = searchMessages.filter(
        (i) => i.chat_repo !== workspaceInfo.repoName,
      );
      return (
        <RepoMessagesList
          currentRepo={currentRepoList}
          otherRepo={otherRepoList}
        />
      );
    }

    return searchMessages.map((item, index) => (
      <MessageItem key={`${item._id}-${index}`} item={item} index={index} />
    ));
  }, [
    loading,
    searchKeyword,
    renderSessions,
    currentSession?._id,
    // editValue,
    // editId,
    handleDelete,
    handleSelectSession,
    // removeId,
    isStreaming,
    isProcessing,
    isTerminalProcessing,
    isSearching,
    updateTopic,
    searchMessages,
    handleSelectSessionAndScrollToMessage,
    selectedMessageId,
    searchField,
    filterSessions,
    workspaceInfo,
    chatType,
    currentRepoOpen,
    otherRepoOpen,
  ]);

  const loadMore = React.useCallback(
    async (page: number) => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
      const controller = new AbortController();
      try {
        setScrollLoading(true);
        const params = {
          _num: 10,
          _page: page,
          _sort_by: '-metadata.create_time',
          [searchField.value]: searchKeyword.trim(),
          chat_type: chatType,
        };
        if (searchField.value === SearchField.Topic) {
          params._exclude = 'data';
        }
        const data = await getHistories(params, controller.signal);
        if (!data.items.length) {
          setIsNext(false);
        } else {
          setSearchSessions((prev) => [...prev, ...data.items]);
        }
        setScrollLoading(false);
      } catch (error) {
        setSearchSessions([]);
        setScrollLoading(false);
        console.error(error);
      }
    },
    [searchKeyword, searchField.value, chatType],
  );

  const disabled = React.useMemo(() => {
    return isStreaming || isProcessing || isTerminalProcessing;
  }, [isStreaming, isProcessing, isTerminalProcessing]);

  return (
    <Tooltip label="历史会话" isDisabled={isOpen}>
      <div
        className="inline-block relative chat-histories-element"
        ref={popoverRef}
        onClick={(e) => {
          e.stopPropagation();
        }}
      >
        <Popover
          placement="bottom-end"
          closeOnBlur={true}
          isOpen={isOpen}
          isLazy
          onClose={() => {
            setIsOpen(false);
            handleReset();
          }}
          matchWidth
        >
          <PopoverTrigger>
            <IconButton
              aria-label="历史会话"
              size="xs"
              icon={<Icon as={TbClockHour3} size="sm" />}
              onClick={handleOpenPopover}
              isDisabled={disabled}
              bg="none"
              color="text.default"
            />
          </PopoverTrigger>
          <Portal>
            <PopoverContent
              style={{
                position: 'absolute',
                right: '-40px',
                ...calcScreenWidth,
              }}
              zIndex="100"
            >
              <PopoverHeader fontWeight="bold" border="0">
                历史会话
              </PopoverHeader>
              <PopoverCloseButton
                onClick={() => {
                  setIsOpen(false);
                  handleReset();
                }}
              />
              <Box p="2" display="flex">
                <Select
                  className="w-[120px]"
                  size="sm"
                  placeholder="请选择搜索类型"
                  value={searchField}
                  options={searchOptions}
                  onChange={(v) => {
                    if (!v) return;
                    setSearchField(v);
                  }}
                  components={{
                    DropdownIndicator: () => (
                      <div className="mr-1">
                        <Icon as={RiArrowDownSLine} size="xs" />
                      </div>
                    ),
                    IndicatorSeparator: () => null,
                  }}
                ></Select>
                <Input
                  value={searchKeyword}
                  size="sm"
                  placeholder="请输入会话名称或对话关键字"
                  onInput={(e) => {
                    const keyword = e.currentTarget.value;
                    setSearchKeyword(keyword);
                  }}
                />
              </Box>

              <PopoverBody
                m={2}
                p={2}
                maxH="400px"
                height="auto"
                overflowY="scroll"
                onScroll={(e) => {
                  const { scrollTop, scrollHeight, clientHeight } =
                    e.currentTarget;
                  if (scrollLoading || !isNext) return;
                  if (
                    scrollHeight - scrollTop <= clientHeight + 20 &&
                    searchKeyword.trim()
                  ) {
                    const nextPage = currentPage + 1;
                    loadMore(nextPage);
                    setCurrentPage(nextPage);
                  }
                }}
              >
                <Box
                  maxH="400px"
                  overflowY="auto"
                  key="auto"
                  onScroll={(e) => {
                    const { scrollTop, scrollHeight, clientHeight } =
                      e.currentTarget;
                    if (scrollLoading || !isNext) return;
                    if (
                      scrollHeight - scrollTop <= clientHeight + 20 &&
                      searchKeyword.trim()
                    ) {
                      const nextPage = currentPage + 1;
                      loadMore(nextPage);
                      setCurrentPage(nextPage);
                    }
                  }}
                >
                  <VStack align="stretch">
                    {renderSearchItem}
                    {searchKeyword.trim().length ? (
                      <Box
                        display="flex"
                        justifyContent="center"
                        fontSize="12px"
                        color="text.default"
                      >
                        {scrollLoading ? <Spinner size="sm" /> : null}
                        {!isNext ? <Text>没有更多数据了</Text> : null}
                      </Box>
                    ) : null}
                  </VStack>
                </Box>
              </PopoverBody>
            </PopoverContent>
          </Portal>
        </Popover>
      </div>
    </Tooltip>
  );
});

